1	// claim-office.ts
2	
3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type Item = {
5	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
6	  material?: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const INSURANCE_SURCHARGE_RATE = 0.1;
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PRICE = 60;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	function nonComponentItemPremium(item: Item): number {
29	  const base = BASE_PREMIUMS[item.type];
30	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
31	  return base + curseSurcharge;
32	}
33	
34	function componentBasePremium(count: number, unitPrice: number): number {
35	  return count === COMPONENT_BLOCK_SIZE
36	    ? COMPONENT_BLOCK_PRICE
37	    : count * unitPrice;
38	}
39	
40	function itemsBasePremium(items: Item[]): number {
41	  const componentCounts: Record<string, number> = {};
42	  let nonComponentBase = 0;
43	  for (const item of items) {
44	    if (COMPONENT_TYPES.has(item.type)) {
45	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
46	    } else {
47	      nonComponentBase += nonComponentItemPremium(item);
48	    }
49	  }
50	  const componentBase = Object.entries(componentCounts).reduce(
51	    (total, [type, count]) =>
52	      total + componentBasePremium(count, BASE_PREMIUMS[type]),
53	    0
54	  );
55	  return nonComponentBase + componentBase;
56	}
57	
58	export function quote(_customer: Customer, items: Item[]): number {
59	  const itemsBase = itemsBasePremium(items);
60	  const insuranceSurcharge = itemsBase * INSURANCE_SURCHARGE_RATE;
61	  return Math.ceil(itemsBase + insuranceSurcharge + PROCESSING_FEE);
62	}
